Function isPalindrome(num, count = 0) {
  if (num.toString().length <= 1 || count === 20) {
    return true;
  }
  const stringNum = num.toString();
  const firstDigit = stringNum.substring(0, 1);
  const lastDigit = stringNum.substring(stringNum.length - 1);
  if (firstDigit !== lastDigit) {
    return false;
  }
  const newNum = stringNum.substring(1, stringNum.length - 1);
  return isPalindrome(parseInt(newNum), count + 1);
} 

// Example usage:
const num = 123454321;
console.log(isPalindrome(num)); // Output: true

// Define a function that accepts an array of strings
function capitalizeArray(arr: string[]): string[] {
  // Define an output array
  const result: string[] = [];

  // Check if the input array is empty
  if (arr.length === 0) {
    throw new Error("Input array is empty");
  }

  // Iterate through each string in the input array
  for (let I = 0; I < arr.length; i++) {
    const str = arr[i];

    // Check if the current element is not a string
    if (typeof str !== "string") {
      throw new Error(`Invalid input at index ${i}: ${str} is not a string`);
    }

    // Capitalize the first letter of the string and add it to the output array
    result.push(str.charAt(0).toUpperCase() + str.slice(1));
  }

  // Return the capitalized array
  return result;
}

// Define an array of strings
const inputArray = ["hello", "world", "typescript"];

// Call the capitalizeArray function with the input array
const capitalizedArray = capitalizeArray(inputArray);

// Output the capitalized array to the console
console.log(capitalizedArray); // Output: ["Hello", "World", "Typescript"]
